### Setting Up Routing

Angular Router enables navigation between views. Configure routes in an array passed to `RouterModule.forRoot()`:

```typescript
import { RouterModule, Routes } from '@angular/router';
import { HomeComponent } from './home/home.component';
import { AboutComponent } from './about/about.component';

const routes: Routes = [
  { path: '', component: HomeComponent },
  { path: 'about', component: AboutComponent },
  { path: '**', redirectTo: '' }
];

@NgModule({
  imports: [RouterModule.forRoot(routes)],
  exports: [RouterModule]
})
export class AppRoutingModule { }
```

### Route Configuration Options

| Property | Type | Description |
|----------|------|-------------|
| `path` | string | URL path segment |
| `component` | class | Component to render |
| `redirectTo` | string | Redirect to another route |
| `pathMatch` | 'full' \| 'prefix' | How to match the path |
| `children` | Routes | Child/nested routes |
| `loadChildren` | () => import() | Lazy load feature module |
| `canActivate` | Guards[] | Route protection |
| `data` | object | Static route data |

### Router Outlet

The `<router-outlet>` directive tells Angular where to render routed components:
```html
<!-- app.component.html -->
<app-header></app-header>
<router-outlet></router-outlet>
<app-footer></app-footer>
```

### Navigation

**Using `routerLink` in templates:**
```html
<a routerLink="/about" routerLinkActive="active">About</a>
<a [routerLink]="['/user', userId]">User Profile</a>
<a [routerLink]="{ outlets: { sidebar: ['chat'] } }">Chat</a>
```

**`routerLinkActive`** — Adds a CSS class when the link is active:
```html
<a routerLink="/dashboard" routerLinkActive="active-link" [routerLinkActiveOptions]="{ exact: true }">
  Dashboard
</a>
```

**Using the Router service programmatically:**
```typescript
import { Router } from '@angular/router';

@Component({...})
export class LoginComponent {
  constructor(private router: Router) {}

  onLogin() {
    this.router.navigate(['/dashboard']);
    this.router.navigateByUrl('/dashboard');
  }
}
```

### Route Parameters

Use `ActivatedRoute` to access route parameters:

```typescript
import { ActivatedRoute } from '@angular/router';

@Component({...})
export class UserDetailComponent implements OnInit {
  userId: string;

  constructor(private route: ActivatedRoute) {}

  ngOnInit() {
    // Snapshot (one-time)
    this.userId = this.route.snapshot.paramMap.get('id')!;

    // Observable (reacts to changes)
    this.route.paramMap.subscribe(params => {
      this.userId = params.get('id')!;
    });

    // Query params
    this.route.queryParamMap.subscribe(params => {
      const page = params.get('page');
    });

    // Route data
    this.route.data.subscribe(data => {
      console.log(data); // resolved data
    });
  }
}
```

### Route Definition with Parameters

```typescript
{ path: 'user/:id', component: UserDetailComponent }
{ path: 'search', component: SearchComponent }  // /search?q=angular
```

